    /// GeomAbs_C1
    /// GeomAbs_C2
    pub fn new_int_shape(
        WorkDegree: i32,
        ConstraintOrder: crate::geom_abs::Shape,
    ) -> crate::OwnedPtr<Self> {
        unsafe {
            crate::OwnedPtr::from_raw(crate::ffi::PLib_JacobiPolynomial_ctor_int_shape(
                WorkDegree,
                ConstraintOrder.into(),
            ))
        }
    }

