    /// W(t) Q(t)  obtained  by   missing  the   coefficients of  JacCoeff   from
    /// NewDegree +1 to Degree
    pub fn max_error(&self, Dimension: i32, JacCoeff: &mut f64, NewDegree: i32) -> f64 {
        unsafe {
            crate::ffi::PLib_JacobiPolynomial_max_error(
                self as *const Self,
                Dimension,
                JacCoeff,
                NewDegree,
            )
        }
    }

