    /// In this case NewDegree = MaxDegree
    pub fn reduce_degree(
        &self,
        Dimension: i32,
        MaxDegree: i32,
        Tol: f64,
        JacCoeff: &mut f64,
        NewDegree: &mut i32,
        MaxError: &mut f64,
    ) {
        unsafe {
            crate::ffi::PLib_JacobiPolynomial_reduce_degree(
                self as *const Self,
                Dimension,
                MaxDegree,
                Tol,
                JacCoeff,
                NewDegree,
                MaxError,
            )
        }
    }

